import React, { useState } from 'react';

export default function AudioExtractor() {
  const [url, setUrl] = useState<string>('');
  const [loading, setLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);

  // Production dynamic base-url resolver
  const getApiUrl = () => {
    if (process.env.NODE_ENV === 'production') {
      return '/extract'; // Uses relative path when unified under a single root origin
    }
    return 'http://localhost:5000/extract'; // Development fallback
  };

  const handleDownload = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (!url.trim()) return;

    setLoading(true);
    setError(null);

    try {
      const response = await fetch(getApiUrl(), {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ url }),
      });

      if (!response.ok) {
        const errData = await response.json().catch(() => ({}));
        throw new Error(errData.error || 'The server encountered an extraction error.');
      }

      const disposition = response.headers.get('content-disposition') || response.headers.get('Content-Disposition');
      let filename = 'audio.mp3';

      if (disposition) {
        // Safe decoding for characters parsed via dynamic encodeURIComponent strings from server
        const filenameMatch = disposition.match(/filename[^;=\n]*=((['"]).*?\2|[^;\n]*)/);
        if (filenameMatch && filenameMatch[1]) {
          filename = decodeURIComponent(filenameMatch[1].replace(/['"]/g, '').trim());
        }
      }

      const blob = await response.blob();
      const downloadUrl = window.URL.createObjectURL(blob);

      const link = document.createElement('a');
      link.href = downloadUrl;
      link.setAttribute('download', filename);

      document.body.appendChild(link);
      link.click();
      link.remove();

      window.URL.revokeObjectURL(downloadUrl);
      setUrl('');
    } catch (err: any) {
      setError(err.message || "An unexpected dynamic error occurred during extraction.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={styles.page}>
      <div style={styles.backgroundGlow} />
      <div style={styles.card}>
        <div style={styles.badge}>Audio extraction</div>
        <h1 style={styles.title}>Turn any video into a polished MP3</h1>

        <p style={styles.subtitle}>
          Paste a video URL to extract clear audio in seconds.
        </p>

        <form onSubmit={handleDownload} style={styles.searchBox}>
          <input
            style={styles.input}
            type="text"
            placeholder="Paste video URL here..."
            value={url}
            onChange={(e: React.ChangeEvent<HTMLInputElement>) => setUrl(e.target.value)}
            disabled={loading}
          />

          <button
            type="submit"
            style={styles.button}
            disabled={loading || !url.trim()}
          >
            {loading ? "Extracting..." : "Extract MP3"}
          </button>
        </form>

        <div style={styles.infoRow}>
          <span style={styles.infoPill}>⚡ Stream delivery</span>
          <span style={styles.infoPill}>🎵 192kbps MP3</span>
          <span style={styles.infoPill}>🔒 Secure processing</span>
        </div>

        {error && <div style={styles.errorBox}>{error}</div>}
        {loading && (
          <div style={styles.loadingBox}>Processing and streaming your audio...</div>
        )}
      </div>
    </div>
  );
}

